import asyncio

async def safe_task():
    try:
        print('Tapşırıq başlayır')
        await asyncio.sleep(1)
        print('Tapşırıq bitdi')
    except asyncio.CancelledError:
        print('Tapşırıq ləğv edildi')

async def main():
    task = asyncio.create_task(safe_task())
    await asyncio.sleep(0.5)
    task.cancel()
    try:
        await task
    except asyncio.CancelledError:
        print('Tapşırıq ləğvi təsdiqləndi')

if platform.system() == 'Emscripten':
    asyncio.ensure_future(main())
else:
    asyncio.run(main())

